        /**
         * @param args 
         */
        connect(...args: never[]): any;

        /**
         * Creates a {@link Gio.SocketConnection} subclass of the right type for
         * `socket`.
         * @returns a {@link Gio.SocketConnection}
         */
        connection_factory_create_connection(): SocketConnection;

