    /**
     * {@link Gio.ActionMap} is an interface for action containers.
     * 
     * The {@link Gio.ActionMap} interface is implemented by {@link Gio.ActionGroup}
     * implementations that operate by containing a number of named
     * {@link Gio.Action} instances, such as {@link Gio.SimpleActionGroup}.
     * 
     * One useful application of this interface is to map the
     * names of actions from various action groups to unique,
     * prefixed names (e.g. by prepending "app." or "win.").
     * This is the motivation for the ‘Map’ part of the interface
     * name.
     * @gir-type Interface
     * @since 2.32
     */
    interface ActionMap extends GObject.Object, ActionMap.Interface {

        // Methods
        /**
         * Adds an action to the `action_map`.
         * 
         * If the action map already contains an action with the same name
         * as `action` then the old action is dropped from the action map.
         * 
         * The action map takes its own reference on `action`.
         * @param action a {@link Gio.Action}
         */
        add_action(action: Action): void;

        /**
         * A convenience function for creating multiple simple actions. 
         * See Gio.ActionEntryObj for the structure of the action entry.
         * @param entries Array of action entries to add
         */
        add_action_entries(entries: ActionEntryObj[]): void;

        /**
         * Looks up the action with the name `action_name` in `action_map`.
         * 
         * If no such action exists, returns `NULL`.
         * @param action_name the name of an action
         * @returns a {@link Gio.Action}
         */
        lookup_action(action_name: string): (Action | null);

        /**
         * Removes the named action from the action map.
         * 
         * If no action of this name is in the map then nothing happens.
         * @param action_name the name of the action
         */
        remove_action(action_name: string): void;

        /**
         * Remove actions from a {@link Gio.ActionMap}. This is meant as the reverse of
         * {@link Gio.ActionMap.add_action_entries}.
         * 
         * 
         * ```c
         * static const GActionEntry entries[] = {
         *     { "quit",         activate_quit              },
         *     { "print-string", activate_print_string, "s" }
         * };
         * 
         * void
         * add_actions (GActionMap *map)
         * {
         *   g_action_map_add_action_entries (map, entries, G_N_ELEMENTS (entries), NULL);
         * }
         * 
         * void
         * remove_actions (GActionMap *map)
         * {
         *   g_action_map_remove_action_entries (map, entries, G_N_ELEMENTS (entries));
         * }
         * ```
         * @param entries a pointer to   the first item in an array of {@link Gio.ActionEntry} structs
         */
        remove_action_entries(entries: ActionEntry[]): void;
    }


