    /**
     * {@link Gio.DebugController} is an interface to expose control of debugging features and
     * debug output.
     * 
     * It is implemented on Linux using {@link Gio.DebugControllerDBus}, which
     * exposes a D-Bus interface to allow authenticated peers to control debug
     * features in this process.
     * 
     * Whether debug output is enabled is exposed as
     * {@link Gio.DebugController.debug_enabled}. This controls
     * {@link GLib.log_set_debug_enabled} by default. Application code may
     * connect to the `GObject.Object::notify` signal for it
     * to control other parts of its debug infrastructure as necessary.
     * 
     * If your application or service is using the default GLib log writer function,
     * creating one of the built-in implementations of {@link Gio.DebugController} should be
     * all that’s needed to dynamically enable or disable debug output.
     * @gir-type Interface
     * @since 2.72
     */
    interface DebugController extends Initable {

        // Properties
        /**
         * `true` if debug output should be exposed (for example by forwarding it to
         * the journal), `false` otherwise.
         * @since 2.72
         * @default false
         */
        get debug_enabled(): boolean;
        set debug_enabled(val: boolean);

        /**
         * `true` if debug output should be exposed (for example by forwarding it to
         * the journal), `false` otherwise.
         * @since 2.72
         * @default false
         */
        get debugEnabled(): boolean;
        set debugEnabled(val: boolean);

        // Methods
        /**
         * Get the value of {@link Gio.DebugController.debug_enabled}.
         * @returns `true` if debug output should be exposed, `false` otherwise
         */
        get_debug_enabled(): boolean;

        /**
         * Set the value of {@link Gio.DebugController.debug_enabled}.
         * @param debug_enabled `true` if debug output should be exposed, `false` otherwise
         */
        set_debug_enabled(debug_enabled: boolean): void;
    }


